import React from "react";
import UploadForm from "./components/UploadForm";
import InvoiceList from "./components/InvoiceList";
import Dashboard from "./components/Dashboard";

function App() {
    return (
        <div>
            <h1>Invoice Extractor</h1>
            <UploadForm />
            <InvoiceList />
            <Dashboard />
        </div>
    );
}

export default App;
